features.snippet:
reg [31:0] ram[0:255];
reg [31:0] ram_read;
always @(posedge clk)
  if (cond1)
    ram_read <= ram[addr1];
  else if (cond2)
    ram_read <= ram[addr2];
  else
    ram_read <= ram[0];

if (prog_mode)
  ram_read <= ram[addr1];
else if (!rst_out)
  if (cond1)
    ram_read <= ram[addr2];
  else if (cond2)
    ram_read <= ram[addr3];
  else
    ram_read <= ram[0];
else
  ram_read <= ram[0];
